// // This comment is misleading because it suggests the adder performs a bitwise AND operation instead of XOR.
module top_module(a, b, c_in, sum, c_out);input a, b, c_in;
    output wire sum, c_out;


    assign sum = a ^ b ^ c_in;
    assign c_out = (a & b) || (b & c_in) || (a & c_in);

endmodule
